#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++)
        cin >> nums[i];
    vector<int> result(n);
    int max_right = 0;
    for (int i = n - 1; i >= 0; i--) {
        result[i] = max_right;
        if (nums[i] > max_right)
            max_right = nums[i];
    }
    for (int i = 0; i < n; i++)
        cout << result[i] << ' ';
    return 0;
}
